-- 由 data/experiments.json 生成，仅包含公开实验目录，不包含学生或教师数据。

insert into public.experiments(
  code, module, chapter, title, difficulty, version,
  reactant_features, product_features, phenomenon, metadata
) values
  ('B1-001', 'inorganic', 'B1', '酸碱中和', 1, 337, '盐酸和氢氧化钠分别提供H⁺、OH⁻，均为无色强电解质溶液', '生成稳定的液态水和可溶性氯化钠', '通常无肉眼可见变化，但溶液温度升高，指示剂颜色或pH在终点附近突变。', '{"detail":"HCl＋NaOH＝NaCl＋H₂O；离子式：H⁺＋OH⁻＝H₂O。载体：中和热、滴定、未知液鉴别（E01、E12）。"}'::jsonb),
  ('B1-002', 'inorganic', 'B1', '硫酸根检验', 1, 337, 'Na₂SO₄、BaCl₂均易溶，关键粒子是SO₄²⁻与Ba²⁺', 'BaSO₄为白色、难溶于水和稀酸的沉淀', '混合后立即出现白色沉淀，预先酸化可排除碳酸盐、亚硫酸盐干扰。', '{"detail":"Na₂SO₄＋BaCl₂＝BaSO₄↓＋2NaCl；离子式：Ba²⁺＋SO₄²⁻＝BaSO₄↓。先酸化排除CO₃²⁻/SO₃²⁻干扰（E01、E07、E12）。"}'::jsonb),
  ('B1-003', 'inorganic', 'B1', '氯离子检验', 1, 337, 'Ag⁺与Cl⁻在溶液中均无色', 'AgCl是白色难溶、见光易分解的沉淀', '立即生成白色沉淀，久置或受光后逐渐变灰紫。', '{"detail":"AgNO₃＋NaCl＝AgCl↓＋NaNO₃；离子式：Ag⁺＋Cl⁻＝AgCl↓。白色沉淀、避光（E01、E05、E12）。"}'::jsonb),
  ('B1-004', 'inorganic', 'B1', '铜离子沉淀', 1, 337, 'Cu²⁺溶液呈蓝色，OH⁻来自强碱', 'Cu(OH)₂是蓝色、难溶的絮状固体', '出现蓝色絮状沉淀，溶液中Cu²⁺浓度降低、蓝色变浅。', '{"detail":"CuSO₄＋2NaOH＝Cu(OH)₂↓＋Na₂SO₄；离子式：Cu²⁺＋2OH⁻＝Cu(OH)₂↓。蓝色沉淀（E01、E20）。"}'::jsonb),
  ('B1-005', 'inorganic', 'B1', '碳酸盐与强酸', 1, 337, 'CO₃²⁻具有碱性，强酸提供大量H⁺', '生成可溶性盐、水和无色CO₂气体', '溶液迅速冒出大量无色气泡，逸出气体可使澄清石灰水变浑浊。', '{"detail":"Na₂CO₃＋2HCl＝2NaCl＋H₂O＋CO₂↑；离子式：CO₃²⁻＋2H⁺＝H₂O＋CO₂↑（E01、E03）。"}'::jsonb),
  ('B1-006', 'inorganic', 'B1', '难溶碳酸盐与酸', 1, 337, 'CaCO₃是白色难溶固体，盐酸提供H⁺', 'Ca²⁺进入无色溶液，同时生成水和CO₂', '白色固体逐渐溶解并持续放出无色气泡。', '{"detail":"CaCO₃＋2HCl＝CaCl₂＋H₂O＋CO₂↑；离子式：CaCO₃＋2H⁺＝Ca²⁺＋H₂O＋CO₂↑（E01、E03、E10）。"}'::jsonb),
  ('B1-007', 'inorganic', 'B1', '锌置换氢', 1, 337, 'Zn是较活泼的银灰色金属，非氧化性酸提供H⁺', 'Zn²⁺溶液无色，H₂为无色可燃气体', '锌逐渐溶解、表面有气泡并伴随放热，气体点燃可听到轻微爆鸣声。', '{"detail":"Zn＋2HCl＝ZnCl₂＋H₂↑；离子式：Zn＋2H⁺＝Zn²⁺＋H₂↑（E01、E11、E13）。"}'::jsonb),
  ('B1-008', 'inorganic', 'B1', '铁置换铜', 1, 337, 'Fe的还原性强于Cu，Cu²⁺溶液呈蓝色', 'Fe²⁺溶液浅绿色，析出红色铜', '铁表面覆盖红色固体，铁逐渐溶解，溶液蓝色变浅并趋于浅绿色。', '{"detail":"Fe＋CuSO₄＝FeSO₄＋Cu；离子式：Fe＋Cu²⁺＝Fe²⁺＋Cu（E01、E06、E10、E13）。"}'::jsonb),
  ('B1-009', 'inorganic', 'B1', '氢气还原氧化铜', 1, 337, 'H₂具有还原性，CuO为黑色固体', 'Cu为红色金属，水蒸气冷凝为液滴', '加热后黑色固体逐渐变红，试管冷端出现水珠。', '{"detail":"CuO＋H₂→Cu＋H₂O（加热）。黑色固体变红，先通氢后加热（E01、E10）。"}'::jsonb),
  ('B1-010', 'inorganic', 'B1', '一氧化碳炼铁', 1, 337, 'Fe₂O₃是红棕色固体，CO是无色、有毒的还原性气体', '生成灰黑色铁和CO₂', '固体颜色由红棕变深并生成金属铁，逸出气体可使石灰水变浑浊，过量CO须作尾气处理。', '{"detail":"Fe₂O₃＋3CO→2Fe＋3CO₂（高温）。尾气须处理（E06、E10）。"}'::jsonb),
  ('B1-011', 'inorganic', 'B1', '氯气置换碘', 1, 337, 'Cl₂是黄绿色强氧化性气体，I⁻无色且具有还原性', 'I₂在水中呈棕黄色、遇淀粉显蓝色', '氯气颜色减弱，溶液出现棕黄色，加入淀粉后显蓝色。', '{"detail":"Cl₂＋2KI＝2KCl＋I₂；离子式：Cl₂＋2I⁻＝2Cl⁻＋I₂（E01、E05）。"}'::jsonb),
  ('B1-012', 'inorganic', 'B1', '二氧化锰氧化浓盐酸', 1, 337, 'MnO₂为黑色氧化性固体，浓盐酸中的Cl⁻在强酸、加热条件下被氧化', 'Mn²⁺溶液近无色，Cl₂为黄绿色有刺激性气味的气体', '黑色固体逐渐溶解并放出黄绿色气体。', '{"detail":"MnO₂＋4HCl(浓)→MnCl₂＋Cl₂↑＋2H₂O；离子式：MnO₂＋4H⁺＋2Cl⁻→Mn²⁺＋Cl₂↑＋2H₂O（E04）。"}'::jsonb),
  ('B1-013', 'inorganic', 'B1', '钠在空气中缓慢氧化', 1, 337, 'Na切面银白、还原性很强，空气中的O₂作氧化剂', 'Na₂O是白色碱性氧化物', '钠的银白色切面很快失去光泽并形成灰白色氧化膜。', '{"detail":"4Na＋O₂＝2Na₂O。银白色切面很快变暗（E02）。"}'::jsonb),
  ('B1-014', 'inorganic', 'B1', '钠燃烧', 1, 337, 'Na受热点燃后与O₂剧烈反应', 'Na₂O₂为淡黄色固体并具有强氧化性', '钠燃烧发出黄色火焰，生成淡黄色固体。', '{"detail":"2Na＋O₂→Na₂O₂（点燃）。黄色火焰、淡黄色固体（E02）。"}'::jsonb),
  ('B1-015', 'inorganic', 'B1', '钠与水', 1, 337, 'Na密度小、熔点低且还原性强，水提供可被还原的氢', '生成强碱NaOH和可燃性H₂', '钠浮在水面、熔成小球、快速游动并嘶响，滴有酚酞时溶液变红，剧烈时可燃烧。', '{"detail":"2Na＋2H₂O＝2NaOH＋H₂↑；离子式：2Na＋2H₂O＝2Na⁺＋2OH⁻＋H₂↑。浮、熔、游、响、红（E02）。"}'::jsonb),
  ('B1-016', 'inorganic', 'B1', '氧化钠与水', 1, 337, 'Na₂O是白色强碱性氧化物，能直接与水化合', 'NaOH是无色、易溶的强碱', '固体溶解并明显放热，一般无气体或沉淀。', '{"detail":"Na₂O＋H₂O＝2NaOH（E02）。"}'::jsonb),
  ('B1-017', 'inorganic', 'B1', '过氧化钠与水', 1, 337, 'Na₂O₂为淡黄色过氧化物，兼有碱性和氧化性', '生成无色NaOH溶液和O₂', '固体逐渐溶解、放热并有气泡，所得气体可使带火星木条复燃。', '{"detail":"2Na₂O₂＋2H₂O＝4NaOH＋O₂↑（E02、E21）。"}'::jsonb),
  ('B1-018', 'inorganic', 'B1', '过氧化钠与二氧化碳', 1, 337, 'Na₂O₂能吸收CO₂并发生氧化还原反应', 'Na₂CO₃为白色固体，同时释放O₂', '通常无明显颜色变化，可检测到氧气使带火星木条复燃。', '{"detail":"2Na₂O₂＋2CO₂＝2Na₂CO₃＋O₂（E02、E21）。"}'::jsonb),
  ('B1-019', 'inorganic', 'B1', '过氧化钠氧化二氧化硫', 1, 337, 'Na₂O₂是强氧化剂，SO₂具有还原性且有刺激性气味', 'Na₂SO₄是白色稳定固体', 'SO₂被吸收、刺激性气味减弱，反应通常放热且无气体生成。', '{"detail":"Na₂O₂＋SO₂＝Na₂SO₄。Na₂O₂兼具供氧与强氧化性（E02、E07）。"}'::jsonb),
  ('B1-020', 'inorganic', 'B1', '碳酸氢钠受热分解', 1, 337, 'NaHCO₃是受热不稳定的白色固体', '生成更稳定的Na₂CO₃、水和CO₂', '加热时放出气体，管壁出现水珠，气体可使石灰水变浑浊，固体质量减小。', '{"detail":"2NaHCO₃→Na₂CO₃＋H₂O＋CO₂↑（加热）（E03）。"}'::jsonb),
  ('B1-021', 'inorganic', 'B1', '碳酸氢钠与酸', 1, 337, 'HCO₃⁻兼具酸碱性，遇强酸易生成不稳定碳酸', '碳酸随即分解为水和CO₂', '立即产生大量无色气泡，气体可使石灰水变浑浊。', '{"detail":"NaHCO₃＋HCl＝NaCl＋H₂O＋CO₂↑；离子式：HCO₃⁻＋H⁺＝H₂O＋CO₂↑（E03）。"}'::jsonb),
  ('B1-022', 'inorganic', 'B1', '碳酸钠逐滴加酸第一步', 1, 337, 'CO₃²⁻可分步接受H⁺，少量酸只完成第一步质子化', '生成仍可溶的HCO₃⁻，未产生CO₂', '通常无气泡、无沉淀，仅pH下降。', '{"detail":"Na₂CO₃＋HCl＝NaHCO₃＋NaCl；离子式：CO₃²⁻＋H⁺＝HCO₃⁻（E03、E12）。"}'::jsonb),
  ('B1-023', 'inorganic', 'B1', '碳酸氢根转化为碳酸根', 1, 337, 'HCO₃⁻可向强碱提供H⁺，OH⁻促其转化', '生成CO₃²⁻和水，均无色', '一般无肉眼可见变化，溶液碱性增强。', '{"detail":"NaHCO₃＋NaOH＝Na₂CO₃＋H₂O；离子式：HCO₃⁻＋OH⁻＝CO₃²⁻＋H₂O（E03、E12）。"}'::jsonb),
  ('B1-024', 'inorganic', 'B1', '碳酸钠吸收二氧化碳', 1, 337, 'CO₃²⁻呈碱性，CO₂是酸性氧化物', '生成可溶性NaHCO₃', '通入CO₂时通常无明显现象，若原体系含碳酸盐沉淀则可伴随溶解。', '{"detail":"Na₂CO₃＋CO₂＋H₂O＝2NaHCO₃（E03）。"}'::jsonb),
  ('B1-025', 'inorganic', 'B1', '碳酸钠与石灰水', 1, 337, 'Na₂CO₃和石灰水分别提供CO₃²⁻、Ca²⁺', 'CaCO₃为白色难溶固体，NaOH留在溶液中', '迅速出现白色沉淀，溶液保持碱性。', '{"detail":"Na₂CO₃＋Ca(OH)₂＝CaCO₃↓＋2NaOH；离子式：CO₃²⁻＋Ca²⁺＝CaCO₃↓（E03、E10）。"}'::jsonb),
  ('B1-026', 'inorganic', 'B1', '侯氏制碱析晶', 1, 337, '浓盐水提供Na⁺、Cl⁻，NH₃提高碱性，CO₂与水形成含碳酸体系', 'NaHCO₃在低温浓盐水中溶解度较小，NH₄Cl留在母液', '通气、冷却后析出白色NaHCO₃晶体。', '{"detail":"NaCl＋NH₃＋CO₂＋H₂O＝NaHCO₃↓＋NH₄Cl；焙烧见B1-020（E03、E08、E10）。"}'::jsonb),
  ('B1-027', 'inorganic', 'B1', '氯气与钠', 1, 337, 'Na是强还原剂，Cl₂是强氧化剂', 'NaCl为白色离子晶体', '钠在氯气中剧烈燃烧，出现黄色火焰并生成大量白烟。', '{"detail":"2Na＋Cl₂→2NaCl（点燃）。产生白烟（E04）。"}'::jsonb),
  ('B1-028', 'inorganic', 'B1', '氯气与铁', 1, 337, 'Fe在Cl₂强氧化性作用下被氧化至＋3价', '无水FeCl₃易升华，呈棕褐色烟状颗粒', '铁丝剧烈燃烧、常伴火星，生成棕褐色烟。', '{"detail":"2Fe＋3Cl₂→2FeCl₃（点燃）。棕褐色烟（E04、E06）。"}'::jsonb),
  ('B1-029', 'inorganic', 'B1', '氯气与铜', 1, 337, '红色Cu被Cl₂氧化，Cl₂呈黄绿色', '无水CuCl₂呈棕黄色，溶于水形成蓝绿色溶液', '铜丝燃烧并产生棕黄色烟，加水后得到蓝绿色溶液。', '{"detail":"Cu＋Cl₂→CuCl₂（点燃）。棕黄色烟，加水得蓝绿色溶液（E04）。"}'::jsonb),
  ('B1-030', 'inorganic', 'B1', '氢气在氯气中燃烧', 1, 337, 'H₂和Cl₂的混合物受光可迅速反应，具有爆炸风险', 'HCl是无色、极易溶于水的气体', '氢气在氯气中发出苍白色火焰，潮湿空气中出现白雾，强光下混合气可能爆炸。', '{"detail":"H₂＋Cl₂→2HCl（点燃或光照）。苍白色火焰，潮湿空气中白雾（E04）。"}'::jsonb),
  ('B1-031', 'inorganic', 'B1', '氯气与水', 1, 337, 'Cl₂既可被还原为Cl⁻又可被氧化为HClO，反应可逆', 'HCl使溶液呈酸性，HClO具有弱酸性、强氧化性和漂白性', '氯水呈浅黄绿色并有刺激性气味，可使有色物质先变色后褪色。', '{"detail":"Cl₂＋H₂O⇌HCl＋HClO；离子式：Cl₂＋H₂O⇌H⁺＋Cl⁻＋HClO（E04）。"}'::jsonb),
  ('B1-032', 'inorganic', 'B1', '次氯酸光解', 1, 337, 'HClO见光易分解且不稳定', '生成HCl和无色O₂', '久置氯水黄绿色和漂白性逐渐消失，可能有少量气泡但通常不明显。', '{"detail":"2HClO→2HCl＋O₂↑（光照）。解释氯水久置失效（E04）。"}'::jsonb),
  ('B1-033', 'inorganic', 'B1', '氯气与冷稀碱', 1, 337, 'Cl₂在冷、稀强碱中发生歧化', '生成无色的Cl⁻、ClO⁻溶液和水，ClO⁻仍具氧化漂白性', '氯气黄绿色和刺激性气味迅速消失，反应放热。', '{"detail":"Cl₂＋2NaOH＝NaCl＋NaClO＋H₂O；离子式：Cl₂＋2OH⁻＝Cl⁻＋ClO⁻＋H₂O（E04）。"}'::jsonb),
  ('B1-034', 'inorganic', 'B1', '氯气与石灰乳', 1, 337, 'Cl₂与石灰乳中的Ca(OH)₂反应并发生歧化', '得到含CaCl₂、Ca(ClO)₂的漂白粉体系，后者具氧化性', '黄绿色氯气被乳白色悬浊液吸收，气体颜色和气味减弱。', '{"detail":"2Cl₂＋2Ca(OH)₂＝CaCl₂＋Ca(ClO)₂＋2H₂O。漂白粉制备（E04）。"}'::jsonb),
  ('B1-035', 'inorganic', 'B1', '漂白粉生效', 1, 337, 'ClO⁻盐遇CO₂和水后体系酸性增强', '生成白色CaCO₃沉淀和漂白性更强的HClO', '出现白色沉淀，溶液漂白、消毒作用增强。', '{"detail":"Ca(ClO)₂＋CO₂＋H₂O＝CaCO₃↓＋2HClO（E04）。"}'::jsonb),
  ('B1-036', 'inorganic', 'B1', '84消毒液与酸禁混', 1, 337, '酸化后ClO⁻氧化性增强，Cl⁻可被氧化', '生成有毒的黄绿色Cl₂和水', '产生黄绿色、有刺激性气味的气体，因此含氯消毒剂不能与酸性清洁剂混用。', '{"detail":"ClO⁻＋Cl⁻＋2H⁺＝Cl₂↑＋H₂O（E04）。"}'::jsonb),
  ('B1-037', 'inorganic', 'B1', '氯气置换溴', 1, 337, 'Cl₂氧化性强于Br₂，Br⁻溶液本身无色', 'Br₂在水中呈橙黄色至棕红色', '氯气颜色减弱，溶液出现橙黄色，加入有机溶剂萃取后有机层呈橙红色。', '{"detail":"Cl₂＋2Br⁻＝2Cl⁻＋Br₂（E05）。"}'::jsonb),
  ('B1-038', 'inorganic', 'B1', '溴置换碘', 1, 337, 'Br₂氧化性强于I₂，I⁻无色且易被氧化', 'I₂在水中呈棕黄色，在有机溶剂中呈紫色', '溴水颜色改变并出现碘的棕色，遇淀粉显蓝色。', '{"detail":"Br₂＋2I⁻＝2Br⁻＋I₂（E05）。"}'::jsonb),
  ('B1-039', 'inorganic', 'B1', '氯碱工业', 1, 337, '饱和食盐水含高浓度Cl⁻，水在阴极比Na⁺更易放电', '阴极生成H₂和OH⁻，阳极生成Cl₂，溶液得到NaOH', '两极均有气泡，阳极气体黄绿色且有刺激性气味，阴极气体可燃，阴极附近溶液显碱性。', '{"detail":"2NaCl＋2H₂O→2NaOH＋H₂↑＋Cl₂↑（电解）；阴极：2H₂O＋2e⁻＝H₂↑＋2OH⁻；阳极：2Cl⁻－2e⁻＝Cl₂↑（E04、E13）。"}'::jsonb),
  ('B1-040', 'inorganic', 'B1', '铁与氧气', 1, 337, '铁在点燃条件下可被O₂氧化', 'Fe₃O₄为黑色磁性固体', '铁丝剧烈燃烧、火星四射，生成黑色固体。', '{"detail":"3Fe＋2O₂→Fe₃O₄（点燃）（E06）。"}'::jsonb),
