  ('X1-053', 'inorganic', 'X1', '惰性电极电解硫酸铜', 2, 337, 'CuSO₄溶液中Cu²⁺优先在阴极还原，惰性阳极处水被氧化', '生成Cu、O₂和H₂SO₄', '阴极析出红色铜，阳极产生无色气泡，蓝色溶液变浅且酸性增强。', '{"detail":"阴极：2Cu²⁺＋4e⁻＝2Cu；阳极：2H₂O－4e⁻＝O₂↑＋4H⁺；总反应：2CuSO₄＋2H₂O→2Cu＋O₂↑＋2H₂SO₄（E13）。"}'::jsonb),
  ('X1-054', 'inorganic', 'X1', '电解饱和食盐水', 2, 337, '饱和食盐水中Cl⁻浓度高，阴极水比Na⁺易还原', '阴极生成H₂、OH⁻，阳极生成Cl₂，溶液形成NaOH', '两极均冒气泡，阳极气体黄绿色，阴极气体可燃，阴极附近指示剂显碱性。', '{"detail":"阴极：2H₂O＋2e⁻＝H₂↑＋2OH⁻；阳极：2Cl⁻－2e⁻＝Cl₂↑；总反应：2NaCl＋2H₂O→2NaOH＋H₂↑＋Cl₂↑（E04、E13）。"}'::jsonb),
